2200	/// Docker wrapper: remove images.
2201	fn rbtdrc_docker_rmi(refs: &[&str]) -> Result<(), String> {
2202	    let status = Command::new("docker")
2203	        .arg("rmi")
2204	        .args(refs)
2205	        .stdout(Stdio::null())
2206	        .stderr(Stdio::null())
2207	        .status()
2208	        .map_err(|e| format!("docker rmi exec failed: {}", e))?;
2209	    if !status.success() {
2210	        return Err(format!("docker rmi exited {}", status.code().unwrap_or(-1)));
2211	    }
2212	    Ok(())
2213	}
2214	
2215	/// Four-mode integration test — 15-step sequence exercising all four delivery modes.
2216	/// Faithful port of rbtcfm_four_mode_tcase from rbtcfm_FourMode.sh.
2217	fn rbtdrc_four_mode_supply_chain(dir: &Path) -> rbtdre_Verdict {
2218	    rbtdrc_with_ctx(|ctx| {
2219	        let conjure_vessel = "rbev-busybox";
2220	        let bind_vessel = "rbev-bottle-plantuml";
2221	        let graft_vessel = "rbev-graft-demo";
2222	        let conjure_dir = format!("rbev-vessels/{}", conjure_vessel);
2223	        let bind_dir = format!("rbev-vessels/{}", bind_vessel);
2224	        let graft_dir = format!("rbev-vessels/{}", graft_vessel);
2225	
2226	        // Verify vessel directories exist
2227	        for (name, vdir) in [("conjure", &conjure_dir), ("bind", &bind_dir), ("graft", &graft_dir)] {
2228	            if !ctx.project_root().join(vdir).is_dir() {
2229	                return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vdir));
2230	            }
2231	            let _ = std::fs::write(dir.join(format!("step-0-{}-dir.txt", name)), vdir.as_str());
2232	        }
2233	
2234	        // Step 1: Conjure busybox
2235	        let _ = std::fs::write(dir.join("step-01-status.txt"), "conjuring");
2236	        let conjure_result = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_ORDAIN, &[&conjure_dir], &[]) {
2237	            Ok(r) if r.exit_code == 0 => r,
2238	            Ok(r) => return rbtdre_Verdict::Fail(format!("conjure failed (exit {})\n{}", r.exit_code, r.stderr)),
2239	            Err(e) => return rbtdre_Verdict::Fail(format!("conjure invocation: {}", e)),
2240	        };
2241	        let conjure_consec = match rbtdri_read_burv_fact(&conjure_result, RBTDRC_FACT_HALLMARK) {
2242	            Ok(v) => v,
2243	            Err(e) => return rbtdre_Verdict::Fail(format!("step 1: {}", e)),
2244	        };
2245	        let conjure_gar_root = match rbtdri_read_burv_fact(&conjure_result, RBTDRC_FACT_GAR_ROOT) {
2246	            Ok(v) => v,
2247	            Err(e) => return rbtdre_Verdict::Fail(format!("step 1 gar_root: {}", e)),
2248	        };
2249	        let conjure_ark_stem = match rbtdri_read_burv_fact(&conjure_result, RBTDRC_FACT_ARK_STEM) {
2250	            Ok(v) => v,
2251	            Err(e) => return rbtdre_Verdict::Fail(format!("step 1 ark_stem: {}", e)),
2252	        };
2253	        let _ = std::fs::write(dir.join("step-01-conjure-consec.txt"), &conjure_consec);
2254	
2255	        // Step 2: Bind plantuml
2256	        let _ = std::fs::write(dir.join("step-02-status.txt"), "binding");
2257	        let bind_result = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_ORDAIN, &[&bind_dir], &[]) {
2258	            Ok(r) if r.exit_code == 0 => r,
2259	            Ok(r) => return rbtdre_Verdict::Fail(format!("bind failed (exit {})\n{}", r.exit_code, r.stderr)),
2260	            Err(e) => return rbtdre_Verdict::Fail(format!("bind invocation: {}", e)),
2261	        };
2262	        let bind_consec = match rbtdri_read_burv_fact(&bind_result, RBTDRC_FACT_HALLMARK) {
2263	            Ok(v) => v,
2264	            Err(e) => return rbtdre_Verdict::Fail(format!("step 2: {}", e)),
2265	        };
2266	        let _ = std::fs::write(dir.join("step-02-bind-consec.txt"), &bind_consec);
2267	
2268	        // Retrieve conjured image for graft input.
2269	        // Wrest locator is relative-to-cloud-prefix: rbfr_wrest prepends
2270	        // RBRR_CLOUD_PREFIX itself when building the full registry ref.
2271	        let graft_retrieve_locator = format!(
2272	            "{}/{}/{}:{}",
2273	            RBTDRC_GAR_CATEGORY_HALLMARKS, conjure_consec, RBTDRC_ARK_BASENAME_IMAGE, conjure_consec
2274	        );
2275	        match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_WREST, &[&graft_retrieve_locator], &[]) {
2276	            Ok(r) if r.exit_code == 0 => {}
2277	            Ok(r) => return rbtdre_Verdict::Fail(format!("wrest for graft failed (exit {})\n{}", r.exit_code, r.stderr)),
2278	            Err(e) => return rbtdre_Verdict::Fail(format!("wrest invocation: {}", e)),
2279	        }
2280	        // Full local ref for the wrested image: gar_root + prefixed ark_stem + basename:tag.
2281	        // conjure_ark_stem already includes the cloud prefix (see rbfd_FoundryDirectorBuild.sh
2282	        // fact emission using RBGL_HALLMARKS_ROOT).
2283	        let local_image_ref = format!(
2284	            "{}/{}/{}:{}",
2285	            conjure_gar_root, conjure_ark_stem, RBTDRC_ARK_BASENAME_IMAGE, conjure_consec
2286	        );
2287	
2288	        // Step 3: Graft busybox
2289	        let _ = std::fs::write(dir.join("step-03-status.txt"), "grafting");
2290	        let graft_result = match rbtdri_invoke_global(
2291	            ctx,
2292	            RBTDRM_COLOPHON_ORDAIN,
2293	            &[&graft_dir],
2294	            &[("BURE_TWEAK_NAME", "threemodegraft"), ("BURE_TWEAK_VALUE", &local_image_ref)],
2295	        ) {
2296	            Ok(r) if r.exit_code == 0 => r,
2297	            Ok(r) => return rbtdre_Verdict::Fail(format!("graft failed (exit {})\n{}", r.exit_code, r.stderr)),
