            RBTDRM_COLOPHON_FIAT,
            RBTDRM_COLOPHON_BARK,
            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
        ]),
        RBTDRM_FIXTURE_FOUR_MODE => Some(&[
            RBTDRM_COLOPHON_ORDAIN,
            RBTDRM_COLOPHON_ABJURE,
